const s = $input.first().json.stats || {};
const card = (label, value, color, link) => {
  const inner = '<div style="font-size:11px;color:#6b7280;text-transform:uppercase;letter-spacing:.5px">'+label+'</div><div style="font-size:24px;font-weight:bold;color:#1f2937;margin-top:6px">'+(value!=null?value:'-')+'</div>';
  return link ? '<a href="'+link+'" style="text-decoration:none;display:block;background:'+(color||'#f9fafb')+';padding:14px;border-radius:8px;flex:1;min-width:140px;border:1px solid #e5e7eb">'+inner+'</a>'
              : '<div style="background:'+(color||'#f9fafb')+';padding:14px;border-radius:8px;flex:1;min-width:140px">'+inner+'</div>';
};
const section = (title, items) => '<h2 style="color:#374151;font-size:14px;text-transform:uppercase;letter-spacing:1px;margin:24px 0 8px">'+title+'</h2><div class="links">'+items+'</div>';
const link = (href, label, descr) => '<a href="'+href+'" style="display:block;background:white;padding:12px 16px;border-radius:6px;text-decoration:none;color:#1f2937;border:1px solid #e5e7eb;flex:1;min-width:240px"><div style="font-weight:600;font-size:14px">'+label+'</div><div style="font-size:12px;color:#6b7280;margin-top:2px">'+descr+'</div></a>';
const html = '<!DOCTYPE html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>ArquitAI Admin</title>' +
'<style>body{font-family:-apple-system,Arial,sans-serif;max-width:1100px;margin:24px auto;padding:16px;color:#1f2937;background:#f3f4f6}h1{color:#0f172a;margin:0}.cards{display:flex;gap:12px;flex-wrap:wrap;margin:16px 0}.links{display:flex;gap:10px;flex-wrap:wrap}.meta{color:#64748b;font-size:13px}a:hover{background:#eef2ff !important}</style>' +
'</head><body>' +
'<h1>ArquitAI Admin</h1>' +
'<div class="meta">Estudio Damian Martinez — ' + new Date().toLocaleString('es-ES') + '</div>' +
'<div class="cards">' +
  card('Proyectos activos', s.projects_active||0, '#eef2ff') +
  card('Critical unresolved', s.critical_unresolved||0, (s.critical_unresolved||0)>0?'#fee2e2':'#f0fdf4') +
  card('IPs bloqueadas', s.ips_blocked||0, (s.ips_blocked||0)>0?'#fef3c7':'#f0fdf4') +
  card('Consultas pending', s.consultations_pending||0, (s.consultations_pending||0)>0?'#fef3c7':null) +
  card('Aftercare urgent', s.aftercare_urgent||0, (s.aftercare_urgent||0)>0?'#fee2e2':null) +
  card('Errores 24h', s.errors_24h||0, (s.errors_24h||0)>0?'#fee2e2':null) +
  card('Coste LLM 30d', s.llm_cost_30d||0, '#f0fdf4') +
'</div>' +

section('Dashboards web', 
  link('/webhook/dashboard-html', 'Dashboard estudio', 'KPIs de proyectos, finance, concierge') +
  link('/webhook/security-dashboard-html', 'Security dashboard', 'Eventos, blocklist, top IPs') +
  link('/webhook/llm-costs-html', 'Costes LLM', 'Por agente, proyecto y modelo')
) +

section('Endpoints JSON',
  link('/webhook/dashboard-summary', 'Dashboard JSON', 'Mismo dato del web pero estructurado') +
  link('/webhook/security-dashboard', 'Security JSON', 'Para parser/automatizacion')
) +

section('Operaciones internas',
  '<div style="background:white;padding:12px;border-radius:6px;font-size:13px;color:#374151"><b>Crons activos</b>: 13 (health_check 06:00, blocklist_cleanup 04:00, events_auto_resolve 02:30, access_log_purge 04:30, stuck_executions hourly, data_integrity 05:30, key_rotation_reminder mensual, security_pentest semanal, security_dashboard_alert semanal, events_purge semanal, project_review 6h, qc_review semanal, weekly_summary domingo).</div>' +
  '<div style="background:white;padding:12px;border-radius:6px;font-size:13px;color:#374151"><b>Ultimo pen-test</b>: '+(s.last_pen_test||'(nunca)')+'</div>'
) +

section('Documentacion',
  link('https://github.com/anthropics/claude-code/issues', 'GitHub issues', 'Reportar bugs / pedir features') +
  '<div style="background:white;padding:12px;border-radius:6px;font-size:13px;color:#6b7280">Knowledge base local en <code>studio-multiagente/knowledge/</code></div>'
) +

'<p style="color:#94a3b8;font-size:11px;margin-top:32px;text-align:center">Esta es la pagina de inicio del admin. Todos los enlaces usan tu cookie/header X-API-Key automaticamente.</p>' +
'</body></html>';
return [{ json: { html: html } }];
